def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        weighted_sum = 0.0
        mult_factor = 1.0
        complex_penalty = 0.0
        if ratio > 3:
            base = ratio ** 5
            remainder_mod = capacity % 5
            for x in range(1, int(capacity) + 5):
                if x % 4 == 0:
                    base += np.sin(ratio * x) * (x / (capacity + epsilon))
                elif x % 3 == 0:
                    base -= np.cos(ratio + x / (item + epsilon))
                else:
                    base += np.exp(-x / (ratio + epsilon))
            if capacity % 4 == 0:
                priority = base * 1.25
            else:
                priority = base / 1.3
            for y in range(1, int(item) + 3):
                weighted_sum += ((y ** 2) / (y + capacity + epsilon)) * np.tanh(ratio * y)
            priority += weighted_sum * (remainder_mod + 1)
        elif 2 < ratio <= 3:
            priority = (np.log(capacity + 2) * ratio ** 3) / (capacity + epsilon)
            summ = 0.0
            for n in range(1, int(capacity) + int(item)):
                term = (np.sqrt(n) / (1 + np.exp(-n / (item + epsilon)))) * np.sin(ratio * n)
                if n % 2 == 0:
                    summ += term
                else:
                    summ -= term
            priority += summ
            if item % 2 == 0:
                priority *= 0.95
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 3)
            for m in range(1, int(item) * 2):
                if m % 5 == 0:
                    priority += np.sqrt(m / (capacity + epsilon))
                else:
                    priority -= (m ** 1.5) / (item + epsilon)
            priority = max(priority, 0)
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * (capacity / (item + epsilon))
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + n / (capacity + epsilon)) * np.cos(n)
                if factor < 0:
                    factor = abs(factor)
            priority *= factor
        elif 0.1 < ratio <= 0.5:
            total = 0.0
            sign = 1
            for j in range(1, int(capacity)*2):
                val = (ratio ** j) / (j + epsilon) * np.sin(j)
                total += val * sign
                sign *= -1
            priority = abs(total) + 0.7 * ratio * capacity
        else:
            base = 0
            for t in range(1, int(capacity) + 1):
                val = (ratio ** t) * np.cos(t * ratio) / (t + epsilon)
                if t % 3 == 0:
                    base += val * (-1) ** t
                else:
                    base += val
            priority = abs(base) + 0.3 + np.log1p(capacity + ratio)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff)*2):
                if p % 2 == 0:
                    penalty += np.log(p + 2) * np.sin(p)
                else:
                    penalty -= p * 0.15 * np.cos(p + 1)
            penalty = max(penalty, 0)
            priority += penalty
        if ratio > 1.5 and capacity % 7 == 3:
            priority *= 1.07 ** (capacity % 5)
        if capacity > item * 3:
            priority /= (1 + np.sqrt(capacity / (item + epsilon)))
        scaling = 1.0
        for a in range(1, int(capacity) + 1):
            temp = 0
            for b in range(1, int(item) + 1):
                val = np.tanh((a * b) / (capacity + item + epsilon))
                temp += val * ((-1) ** (a + b))
                if temp > 5:
                    break
            scaling *= (1 + temp / (capacity + epsilon))
            if scaling > 100:
                scaling = 100
                break
        priority *= scaling
        priorities[i] = priority
    return priorities
